// 🎵 FUNÇÕES AUXILIARES PARA FORMATAR DADOS
// ═══════════════════════════════════════════════════════════════
// Formata segundos para duração legível (ex: 4 minutos e 19 segundos)
const formatDuration = (seconds) => {
  if (!seconds || isNaN(seconds)) return 'Não informado';
  const horas = Math.floor(seconds / 3600);
  const minutos = Math.floor((seconds % 3600) / 60);
  const segs = seconds % 60;
  let resultado = [];
  if (horas > 0) resultado.push(`${horas} hora${horas > 1 ? 's' : ''}`);
  if (minutos > 0) resultado.push(`${minutos} minuto${minutos > 1 ? 's' : ''}`);
  if (segs > 0 || resultado.length === 0) resultado.push(`${segs} segundo${segs > 1 ? 's' : ''}`);
  return resultado.join(', ');
};
// Formata data do YouTube para formato brasileiro (ex: 15 de julho de 2011)
const formatDate = (dateString) => {
  if (!dateString) return 'Não informado';
  try {
    const date = new Date(dateString);
    if (isNaN(date.getTime())) return 'Não informado';
    const meses = [
      'janeiro', 'fevereiro', 'março', 'abril', 'maio', 'junho',
      'julho', 'agosto', 'setembro', 'outubro', 'novembro', 'dezembro'
    ];
    const dia = date.getDate();
    const mes = meses[date.getMonth()];
    const ano = date.getFullYear();
    return `${dia} de ${mes} de ${ano}`;
  } catch (e) {
    return 'Não informado';
  }
};
// Resumo da descrição para apenas uma linha
const summarizeDescription = (description) => {
  if (!description) return 'Não informado';
  // Remove quebras de linha e tabs
  let summary = description.replace(/[\n\r\t]+/g, ' ').trim();
  // Limita a ~100 caracteres
  if (summary.length > 100) {
    summary = summary.substring(0, 97) + '...';
  }
  return summary || 'Não informado';
};
// ═══════════════════════════════════════════════════════════════
// 🎵 LAYOUT DO PLAYER DE MÚSICA (iPhone Style)
// ═══════════════════════════════════════════════════════════════
const formatMusicPlayer = (title, artist, duration = null, progress = null, volume = null) => {
  const maxWidth = 42;
  const truncate = (text, maxLen) => {
    if (!text || typeof text !== 'string') return '';
    if (text.length <= maxLen) return text;
    return text.substring(0, maxLen - 3) + '...';
  };
  const safeTitle = title || 'Música';
  const safeArtist = artist || 'Artista';
  const titleDisplay = truncate(safeTitle, maxWidth - 5);
  const artistDisplay = truncate(safeArtist, maxWidth);
  const totalSeconds = duration || 194;
  const currentSeconds = progress !== null ? Math.floor(totalSeconds * progress) : 72;
  const barWidth = 35; // Reduzido em 5 caracteres
  const filledBars = Math.floor((currentSeconds / totalSeconds) * barWidth);
  const emptyBars = barWidth - filledBars;
  const progressBar = '─'.repeat(filledBars) + '●' + '─'.repeat(Math.max(0, emptyBars - 1));
  const volPercent = volume !== null ? volume : 75;
  const volFilled = Math.floor((volPercent / 100) * 30);
  const volEmpty = 30 - volFilled;
  const volumeBar = '─'.repeat(volFilled) + '─'.repeat(volEmpty);
  const innerWidth = maxWidth;
  const pad = (str, len) => str + ' '.repeat(Math.max(0, len - str.length));
  const line = (content) => `${pad(content, innerWidth)}`;
  const spacer = () => ' '.repeat(innerWidth + 2);
  const emoji = '🅴';
  // Montar o layout linha por linha
  let player = '';
  // Linha 1: iPhone (com espaços à direita)
  player += ` ${line('iPhone')}\n`;
  // Linha 2: Nome da música + emoji
  const titleWithEmoji = titleDisplay + ' ' + emoji;
  player += ` ${line(titleWithEmoji)}\n`;
  // Linha 3: Artista
  player += ` ${line(artistDisplay)}\n`;
  // Linha 4: Barra de progresso (5 caracteres mais curta)
  player += ` ${line(progressBar)}\n`;
  // Linha 5: Controles (25 espaços antes e depois)
  const controls = '                         ⇆  ◁  ❚❚  ▷  ↻                         ';
  player += ` ${line(controls)}`;
  // Linha 6: Barra de volume
  const volumeLine = `🔈  ${volumeBar}  🔊`;
  player += ` ${line(volumeLine)}`;
  return player;
};
// ═══════════════════════════════════════════════════════════════
// 🚦 SISTEMA DE THROTTLING PARA COMANDOS
// ═══════════════════════════════════════════════════════════════
const commandThrottle = new Map(); // userId -> { count, timestamp }
const checkThrottle = (userId) => {
  const now = Date.now();
  const userData = commandThrottle.get(userId) || { count: 0, timestamp: now };
  // Reset a cada 5 segundos
  if (now - userData.timestamp > 5000) {
    userData.count = 0;
    userData.timestamp = now;
  }
  userData.count++;
  commandThrottle.set(userId, userData);
  // Máximo 3 comandos por 5 segundos
  return userData.count <= 3;
};
// ═══════════════════════════════════════════════════════════════
// 📝 CACHE PARA GROUP DATA (evita ler arquivo toda vez)
// ═══════════════════════════════════════════════════════════════
const groupDataCache = new Map(); // groupId -> { data, timestamp }
const GROUP_CACHE_TTL = 5000; // 5 segundos
const getCachedGroupData = (groupId, loadFn) => {
  const cached = groupDataCache.get(groupId);
  const now = Date.now();
  if (cached && (now - cached.timestamp) < GROUP_CACHE_TTL) {
    return Promise.resolve(cached.data);
  }
  return loadFn().then(data => {
    groupDataCache.set(groupId, { data, timestamp: now });
    return data;
  });
};
const invalidateGroupCache = (groupId) => {
  groupDataCache.delete(groupId);
};
